import{_ as o,o as e,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Advanced Postback Configuration","description":"","frontmatter":{"title":"Advanced Postback Configuration","slug":"advanced-postback-configuration"},"headers":[],"relativePath":"developer-hub/advanced-postback-configuration.md","filePath":"developer-hub/advanced-postback-configuration.md"}'),n={name:"developer-hub/advanced-postback-configuration.md"};function i(s,t,d,l,c,p){return e(),a("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>After enabling basic configurations for your ad network Postbacks, you may want to make more advanced edits to the configuration depending on your specific use case and what types of data you want to filter for your postback. In most cases, the default postback URL generated from your selections is sufficient to provide postback notification to interested parties. But sometimes you may need/want to edit or remove a parameter from the postback URL(s) or append a macro expression/variable to include additional information.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>For <a href="https://help.branch.io/docs/basic-postback-configuration" target="_blank" rel="noreferrer">basic postback configuration instructions</a> or <a href="https://help.branch.io/docs/testing-postbacks" target="_blank" rel="noreferrer">information on testing postbacks</a>, please visit Marketer Hub.</p></div><h4 id="advanced-postback-configuration-examples" tabindex="-1">Advanced Postback Configuration Examples: <a class="header-anchor" href="#advanced-postback-configuration-examples" aria-label="Permalink to &quot;Advanced Postback Configuration Examples:&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Goal</th><th>Reason(s)</th><th>Solution</th></tr></thead><tbody><tr><td>Send your ad partner the actual items that the end-user adds to their cart.</td><td>1. Ad partner can optimize campaigns based off of those items. 2. The basic <strong>Add to Cart</strong> postback template does not include this information.</td><td><a href="./advanced-postback-configuration.html#addingediting-macros">Add Macros</a> for <strong>Content Items</strong>: <code>${(content_items[0].$product_name)!}</code> as the value to an <em>ad-partner-provided</em> query parameter key in the postback URL.</td></tr><tr><td>Only send the <strong>INSTALL</strong> postback for specific agencies.</td><td>Only specific agency-run campaigns should be sending installs to the ad partner.</td><td><a href="./advanced-postback-configuration.html#adding-filters">Add a Filters</a> to the <strong>INSTALL</strong> postback template to specify which agency IDs to filter for.</td></tr><tr><td>Only send a <strong>PURCHASE</strong> postback for a specific coupon.</td><td>Because you have many different coupon codes, you only want to send one type.</td><td><a href="./advanced-postback-configuration.html#custom-filters">Add a Custom Filter</a> to the <strong>PURCHASE</strong> postback template to specify which coupon string is applied to a given <strong>PURCHASE</strong> event to filter for.</td></tr></tbody></table><h2 id="adding-editing-macros" tabindex="-1">Adding/Editing Macros <a class="header-anchor" href="#adding-editing-macros" aria-label="Permalink to &quot;Adding/Editing Macros&quot;">​</a></h2><p>Postback macros are key/value pairs appended to a postback URL as query parameters. With it, ad partners will receive specific data points about the postback to help optimize campaigns. To view all available macros, view our guide on Postback Macros &amp; Functions <a href="./postback-macros-functions.html">here</a>.</p><h3 id="add-pre-built-macros" tabindex="-1">Add Pre-built Macros <a class="header-anchor" href="#add-pre-built-macros" aria-label="Permalink to &quot;Add Pre-built Macros&quot;">​</a></h3><p>You can select a postback URL key from a pre-built list. Once you add your key, the postback macro will be auto-filled. To add a pre-built macro:</p><ol><li>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</li><li>Hover on the three dots icon to the right of the postback and click <strong>Advanced Edit</strong>.</li><li>An <strong>Edit Postback</strong> modal will pop up and you can add pre-built macros in the <strong>Add Pre-built Macros</strong> section. Click the <strong>+ Add Pre-built Macro</strong> button.</li><li>Click <strong>Save</strong> after you finish making macro edits.</li></ol><h3 id="free-form-edit" tabindex="-1">Free Form Edit <a class="header-anchor" href="#free-form-edit" aria-label="Permalink to &quot;Free Form Edit&quot;">​</a></h3><p>If you want to have full control of your postback macros, you can make direct edits through a free-form field. To make a free form edit to a postback URL:</p><ol><li><p>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</p></li><li><p>Hover on the three dots icon to the right of the postback and click <strong>Advanced Edit</strong>.</p></li><li><p>An <strong>Edit Postback</strong> modal will pop up and you can make edits to the <strong>Free Form Edit</strong> field by adding/editing/removing the key-value pairs necessary.</p><ul><li>You must include an <code>&amp;</code> character before each key-value pair you append.</li></ul></li><li><p>Click <strong>Save</strong> after you finish adding your desired macros.</p></li></ol><h3 id="custom-macros" tabindex="-1">Custom Macros <a class="header-anchor" href="#custom-macros" aria-label="Permalink to &quot;Custom Macros&quot;">​</a></h3><p>You can also create any custom macro for your postback URL with any key-value pair. To add a custom macro:</p><ol><li>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</li><li>Hover on the three dots icon to the right of the postback and click <strong>Advanced Edit</strong>.</li><li>An <strong>Edit Postback</strong> modal will pop up and you can add custom macros to the <strong>Add Custom Macros</strong> section. Click the <strong>+ Add Custom Macro</strong> button.</li><li>Click <strong>Save</strong> after you finish adding your desired macros.</li></ol><h2 id="adding-filters" tabindex="-1">Adding Filters <a class="header-anchor" href="#adding-filters" aria-label="Permalink to &quot;Adding Filters&quot;">​</a></h2><p>In order to add a filter, you need to update the postback template:</p><ol><li><p>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</p></li><li><p>Hover on the three dots icon to the right of the postback and click <strong>Advanced Edit</strong>.</p></li><li><p>An <strong>Edit postback</strong> modal will pop up</p></li><li><p>Go to the <strong>Filters</strong> tab. Click the <strong>+ Add New Filter</strong> button.</p><ul><li>Edit your filter <strong>Comparitor</strong> and <strong>Value(s)</strong></li></ul></li><li><p>Click <strong>Save</strong> to apply the filter.</p></li></ol><h3 id="custom-filters" tabindex="-1">Custom Filters <a class="header-anchor" href="#custom-filters" aria-label="Permalink to &quot;Custom Filters&quot;">​</a></h3><p>Custom filters allow you to leverage a wide variety of data points like link data, user data, and event data. Format and spelling are crucial to making sure custom filters work properly, so make sure you&#39;ve taken a look at the data format.</p><p>Creating a custom filter is similar to adding a standard filter. You must select <strong>Custom</strong> when adding a filter.</p><ol><li><p>Type in the key that you&#39;d like to filter on</p><ul><li>You can find all of the keys here. Depending on the key you are filtering on, it may be part of the top-level data (ex. <code>timestamp</code> or it may be nested (ex. <code>event_data.coupon</code>)</li></ul></li><li><p>Set the filter logic (<strong>equals</strong> or <strong>not equals</strong>)</p></li><li><p>Set the input values.</p></li></ol><h2 id="using-http-post-method" tabindex="-1">Using HTTP POST Method <a class="header-anchor" href="#using-http-post-method" aria-label="Permalink to &quot;Using HTTP POST Method&quot;">​</a></h2><p>By default, Branch sends postbacks via the HTTP <code>GET</code> method. You can, however, choose to have the postback sent via the HTTP <code>POST</code> method instead.</p><p>To change the HTTP method to POST:</p><ol><li>Under <strong>Partner Management</strong>, select the partner for whom you want to add/edit their postback.</li><li>Hover on the three dots icon to the right of the postback and click <strong>Advanced Edit</strong>.</li><li>An <strong>Edit postback</strong> modal will pop up</li><li>Go to the <strong>Filters</strong> tab.</li><li>In the <strong>Postback Details</strong> section, change the HTTP method from <strong>GET</strong> to <strong>POST</strong>.</li><li>In the <strong>Headers</strong> tab, click the <strong>+ Add New Header</strong> button to add new headers.</li><li>In the <strong>Body</strong> tab, add any other <a href="./postback-macros-functions.html">Freemarker expressions</a> you&#39;d like.</li><li>In the <strong>Filters</strong> tab, add any filters you&#39;d like.</li><li>Click <strong>Save</strong>.</li></ol>',27)])])}const g=o(n,[["render",i]]);export{u as __pageData,g as default};
